    unique_shorts = {}
    for py, word, freq in shorts:
        key = (py, word)
        if key in unique_shorts:
            unique_shorts[key] = max(unique_shorts[key], freq)
        else:
            unique_shorts[key] = freq

    with open("short_pinyin.txt", "w", encoding="utf-8") as f:
        f.write("# PinyinIME Expanded Short Pinyin Dictionary\n")
        f.write("# Format: pinyin\\tword\\tfrequency\n")
        count = 0
        for (py, word), freq in sorted(unique_shorts.items(), key=lambda x: (x[0][0], -x[1])):
            f.write(f"{py}\\t{word}\\t{freq}\n")
            count += 1
    print(f"Generated short_pinyin.txt with {count} entries.")

